import sys

class ListNode:
    def __init__(self, val: int = 0, next: 'ListNode' = None):
        self.val = val
        self.next = next

class Solution:
    def insertAtHead(self, head: ListNode | None, data: int) -> ListNode:
        new_node = ListNode(data)
        new_node.next = head
        return new_node

def build_linked_list(values):
    head = None
    tail = None
    for v in values:
        node = ListNode(v)
        if head is None:
            head = tail = node
        else:
            tail.next = node
            tail = node
    return head

def linked_list_to_list(head):
    res = []
    cur = head
    while cur:
        res.append(cur.val)
        cur = cur.next
    return res

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    n = int(next(it))
    values = []
    for _ in range(n):
        try:
            values.append(int(next(it)))
        except StopIteration:
            break
    try:
        new_data = int(next(it))
    except StopIteration:
        new_data = 0
    head = build_linked_list(values)
    sol = Solution()
    new_head = sol.insertAtHead(head, new_data)
    result = linked_list_to_list(new_head)
    print(' '.join(map(str, result)))

