#include <bits/stdc++.h>
using namespace std;

struct Node {
    int data;
    Node* next;
    Node(int d) : data(d), next(nullptr) {}
};

class Solution {
public:
    Node* insertAtHead(Node* head, int data) {
        Node* newNode = new Node(data);
        newNode->next = head;
        return newNode;
    }
};

Node* buildList(const vector<int>& vals) {
    Node* head = nullptr;
    Node* tail = nullptr;
    for (int v : vals) {
        Node* node = new Node(v);
        if (!head) {
            head = tail = node;
        } else {
            tail->next = node;
            tail = node;
        }
    }
    return head;
}

vector<int> listToVector(Node* head) {
    vector<int> res;
    while (head) {
        res.push_back(head->data);
        head = head->next;
    }
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals;
    for (int i = 0; i < n; ++i) {
        int x; cin >> x; vals.push_back(x);
    }
    int newData;
    if (!(cin >> newData)) newData = 0;

    Node* head = buildList(vals);
    Solution sol;
    Node* newHead = sol.insertAtHead(head, newData);
    vector<int> out = listToVector(newHead);
    for (size_t i = 0; i < out.size(); ++i) {
        if (i) cout << ' ';
        cout << out[i];
    }
    cout << "\n";
    return 0;
}
